package ir.tahamohamadi.blog.post.api.admin; import ir.tahamohamadi.common.api.PageResponse; import jakarta.validation.*; import jakarta.validation.constraints.*; import org.springframework.web.bind.annotation.*; import org.springframework.http.*; import org.springframework.data.domain.*; import org.springframework.boot.autoconfigure.condition.*; import java.util.*;
@RestController @RequestMapping("/api/v1/admin/blog/posts") @ConditionalOnExpression("!'${spring.autoconfigure.exclude:}'.contains('DataSourceAutoConfiguration')") public class AdminBlogController { final AdminBlogService blog; public AdminBlogController(AdminBlogService blog){this.blog=blog;} @GetMapping public PageResponse<AdminBlogSummary> list(@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(100) int size){return PageResponse.from(blog.list(PageRequest.of(page,size)));} @GetMapping("/{id}") public AdminBlogResponse get(@PathVariable UUID id){return blog.get(id);} @PostMapping public ResponseEntity<AdminBlogResponse> create(@Valid @RequestBody AdminBlogCreateRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(blog.create(r));} @PutMapping("/{id}") public AdminBlogResponse update(@PathVariable UUID id,@Valid @RequestBody AdminBlogUpdateRequest r){return blog.update(id,r);} }
